// Normaliza payload del quoter a columnas planas + payload JSONB completo.
// Fase 6: extrae solarPanels[] (Google Solar API) y dimensiones para análisis posterior.
const src = $input.first().json;
const body = src.body || src;
const q = body || {};
const r = q.results || {};
const b = q.budget || {};
const agpe = q.agpe || {};
const panel = q.panel || {};
const gse = r.googleSolarEstimate || q.googleSolarEstimate || {};
const roof = q.roof || {};

const email = (q.email || '').toString().trim().toLowerCase();
const phone = (q.phone || '').toString().trim();
const name = (q.name || '').toString().trim();
const company = (q.company || '').toString().trim();
if (!email) throw new Error('email requerido');
if (!name) throw new Error('name requerido');

const ip = (src.headers && (src.headers['x-forwarded-for'] || src.headers['x-real-ip'])) || null;
const userAgent = (src.headers && src.headers['user-agent']) || null;

// solarPanels[] puede venir en tres lugares según fase de evolución del frontend:
//   1) q.solarPanels (top-level, futuro)
//   2) q.roof.solarPanels (anidado bajo roof)
//   3) q.results.googleSolarEstimate.solarPanels (vía estimate Google)
// Se sanitiza a un shape mínimo {center,orientation,segmentIndex,yearlyEnergyDcKwh}
// para no inflar el JSONB con campos inestables del API.
function extractSolarPanels() {
  const candidates = [q.solarPanels, roof.solarPanels, gse.solarPanels];
  const arr = candidates.find(c => Array.isArray(c) && c.length > 0);
  if (!arr) return null;
  return arr.slice(0, 500).map(p => ({
    center: p.center && p.center.latitude != null && p.center.longitude != null
      ? { latitude: Number(p.center.latitude), longitude: Number(p.center.longitude) }
      : (p.center && p.center.lat != null && p.center.lng != null
          ? { latitude: Number(p.center.lat), longitude: Number(p.center.lng) }
          : null),
    orientation: p.orientation || null,
    segmentIndex: p.segmentIndex != null ? Number(p.segmentIndex) : null,
    yearlyEnergyDcKwh: p.yearlyEnergyDcKwh != null ? Number(p.yearlyEnergyDcKwh) : null,
  }));
}
const solarPanels = extractSolarPanels();

const panelHeightMeters = gse.panelHeightMeters != null ? Number(gse.panelHeightMeters)
  : (roof.panelHeightMeters != null ? Number(roof.panelHeightMeters) : null);
const panelWidthMeters  = gse.panelWidthMeters  != null ? Number(gse.panelWidthMeters)
  : (roof.panelWidthMeters  != null ? Number(roof.panelWidthMeters)  : null);
const areaM2           = roof.areaM2 != null ? Number(roof.areaM2)
  : (q.availableArea != null ? Number(q.availableArea) : null);
const wholeRoofAreaM2  = roof.wholeRoofAreaM2 != null ? Number(roof.wholeRoofAreaM2) : null;
const imageryQuality   = roof.imageryQuality || gse.imageryQuality || null;
const googleYearlyKwh  = gse.yearlyEnergyDcKwh != null ? Number(gse.yearlyEnergyDcKwh) : null;
const aiProvider       = (q.aiReview && q.aiReview.provider) || q.aiProvider || null;

return [{ json: {
  email, phone, name, company,
  system_type: q.systemType || null,
  monthly_kwh: q.monthlyKwh != null ? Number(q.monthlyKwh) : null,
  operator: q.operator || null,
  dept: q.city || q.dept || null,
  address: q.address || null,
  lat: q.lat != null ? Number(q.lat) : null,
  lon: q.lon != null ? Number(q.lon) : null,
  kwp: r.actKwp != null ? Number(r.actKwp) : null,
  num_panels: r.numPanels != null ? Math.round(Number(r.numPanels)) : null,
  panel_id: panel.id || null,
  production_kwh_month: r.mp != null ? Number(r.mp) : null,
  coverage_pct: r.cov != null ? Number(r.cov) : null,
  shade_index: q.shadeIndex != null ? Number(q.shadeIndex) : null,
  shade_source: q.shadeSource || null,
  total_cop: b.tot != null ? Math.round(Number(b.tot)) : null,
  total_usd: b.budgetUsd != null ? Math.round(Number(b.budgetUsd)) : null,
  section_a_cop: b.sA != null ? Math.round(Number(b.sA)) : null,
  section_b_cop: b.sB != null ? Math.round(Number(b.sB)) : null,
  transport_cop: b.transport != null ? Math.round(Number(b.transport)) : null,
  annual_sav_cop: b.sav != null ? Math.round(Number(b.sav)) : null,
  roi_years: b.roi != null ? Number(b.roi) : null,
  has_excedentes: agpe.excedentes != null ? Number(agpe.excedentes) > 0 : null,
  agpe_category: agpe.agpeCategory || null,
  regulatory_ids: Array.isArray(q.regulatory) ? q.regulatory : [],
  payload: q,
  ip, user_agent: userAgent,
  solar_panels: solarPanels,
  panel_height_meters: panelHeightMeters,
  panel_width_meters: panelWidthMeters,
  area_m2: areaM2,
  whole_roof_area_m2: wholeRoofAreaM2,
  imagery_quality: imageryQuality,
  google_yearly_kwh: googleYearlyKwh,
  ai_provider: aiProvider,
} }];

// Une userId con el payload normalizado.
const norm = $('Normalize payload').first().json;
const u = $input.first().json;
const userId = Number(u.id || u.ID || 0);
if (!userId) throw new Error('upsert users no devolvió id');
return [{ json: { ...norm, user_id: userId } }];

const norm = $('Normalize payload').first().json;
const merged = $('Merge userId').first().json;
const ins = $input.first().json || {};
const quoteId = Number(ins.id || 0);
const panelsCount = Array.isArray(norm.solar_panels) ? norm.solar_panels.length : 0;
return [{ json: {
  ok: true,
  quoteId,
  userId: merged.user_id,
  createdAt: ins.created_at || null,
  contact: { email: norm.email, name: norm.name },
  totals: { kwp: norm.kwp, total_cop: norm.total_cop, num_panels: norm.num_panels },
  solar: {
    panelsPersisted: panelsCount,
    imageryQuality: norm.imagery_quality,
    googleYearlyKwh: norm.google_yearly_kwh,
  },
} }];
